            for j in range(8):
                if (i + j) % 2:
                    self.board[i][j] = 'b'
        for i in range(5, 8):
            for j in range(8):
                if (i + j) % 2:
                    self.board[i][j] = 'r'

    def print_board(self):
        for row in self.board:
            print(' '.join(row))
